helper_lemmas:
proof fn lemma_init_unique(
    id: AbstractEndPoint,
    args: AbstractArgs,
    post1: AbstractHostState,
    post2: AbstractHostState,
)
    requires
        init(post1, id, args),
        init(post2, id, args),
    ensures
        post1 == post2,
{
    let end_points = parse_args(args);
    assert(end_points is Some);
    assert(end_points.unwrap().len() > 0);
    let root_identity = end_points.unwrap()[0];
    let params = AbstractParameters::static_params();
    let target = AbstractHostState{
        constants: AbstractConstants{
            root_identity,
            host_ids: end_points.unwrap(),
            params,
            me: id,
        },
        delegation_map: AbstractDelegationMap::init(root_identity),
        h: Map::empty(),
        sd: SingleDelivery::init(),
        received_packet: None,
        num_delegations: 1,
        received_requests: seq![],
    };
    assert(post1 == target);
    assert(post2 == target);
}

proof fn lemma_init_ensures_equal(
    netc: &NetClient,
    args: Args,
    r1: Option<HostState>,
    r2: Option<HostState>,
)
    requires
        HostState::init_ensures(netc, args, r1),
        HostState::init_ensures(netc, args, r2),
        r1 is Some <==> r2 is Some,
    ensures
        det_real_init_impl_equal(r1, r2),
{
    match (r1, r2) {
        (Some(hs1), Some(hs2)) => {
            lemma_init_unique(
                netc.my_end_point(),
                abstractify_args(args),
                hs1@,
                hs2@,
            );
            assert(hs1@ == hs2@);
            assert(det_real_init_impl_equal(r1, r2));
        },
        (None, None) => {
            assert(det_real_init_impl_equal(r1, r2));
        },
        _ => {
            assert(false);
        }
    }
}
